const accounts = $json.facebook_ad_account_ids || [];
const locationId = $json.location_id;
const token = $json.meta_capi_access_token;

// Date range: yesterday
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toISOString().split('T')[0];

const results = [];
for (const accountId of accounts) {
  results.push({
    accountId: accountId.startsWith('act_') ? accountId : `act_${accountId}`,
    locationId,
    token,
    dateStr,
    sinceDate: dateStr,
    untilDate: dateStr
  });
}
return results;

const data = $json.data || [];
const locationId = $('Prepare API Call').first().json.locationId;
const dateStr = $('Prepare API Call').first().json.dateStr;

return data.map(row => {
  const actions = row.actions || [];
  const getAction = (type) => {
    const found = actions.find(a => a.action_type === type);
    return found ? parseInt(found.value, 10) : 0;
  };

  return {
    json: {
      ad_id: row.ad_id,
      ad_name: row.ad_name || 'N/A',
      adset_id: row.adset_id,
      adset_name: row.adset_name,
      campaign_id: row.campaign_id,
      campaign_name: row.campaign_name,
      account_name: row.account_name || $('Prepare API Call').first().json.accountId,
      impressions: parseInt(row.impressions || '0', 10),
      clicks: parseInt(row.clicks || '0', 10),
      spend: parseFloat(row.spend || '0'),
      cpc: parseFloat(row.cpc || '0'),
      cpm: parseFloat(row.cpm || '0'),
      reach: parseInt(row.reach || '0', 10),
      frequency: parseFloat(row.frequency || '0'),
      conversas_iniciadas: getAction('onsite_conversion.messaging_conversation_started_7d'),
      form_submissions: getAction('leadgen_submitted'),
      post_reactions: getAction('post_reaction'),
      data_relatorio: dateStr,
      location_id: locationId
    }
  };
});
